import React, { useState, useEffect } from 'react';
import { Search, Info, Globe, Sun, Moon, ZoomIn, ZoomOut, RefreshCcw, X, Check, Star, Zap } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { Language } from '../translations';

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [zoomLevel, setZoomLevel] = useState(100);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isLangMenuOpen, setIsLangMenuOpen] = useState(false);
  const [isInfoModalOpen, setIsInfoModalOpen] = useState(false);
  const { language, setLanguage, t } = useLanguage();

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark') {
      setIsDarkMode(true);
    }
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const handleZoomIn = () => setZoomLevel(prev => Math.min(prev + 20, 150));
  const handleZoomOut = () => setZoomLevel(prev => Math.max(prev - 20, 60));
  const resetZoom = () => setZoomLevel(100);
  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    setIsLangMenuOpen(false);
  };

  const languages: { code: Language; label: string }[] = [
    { code: 'id', label: 'ID (Indonesia)' },
    { code: 'en', label: 'EN (English)' },
    { code: 'ar', label: 'AR (Arabic)' },
    { code: 'ms', label: 'MS (Malay)' },
    { code: 'zh', label: 'ZH (Chinese)' },
    { code: 'ja', label: 'JA (Japanese)' },
  ];

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'} relative font-sans overflow-x-hidden`}>
      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <div className={`absolute top-0 -left-1/4 w-[1000px] h-[1000px] rounded-full blur-[120px] opacity-20 ${isDarkMode ? 'bg-blue-900/40' : 'bg-blue-200/50'}`} />
        <div className={`absolute bottom-0 -right-1/4 w-[1000px] h-[1000px] rounded-full blur-[120px] opacity-20 ${isDarkMode ? 'bg-indigo-900/40' : 'bg-indigo-200/50'}`} />
        <div 
          className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05]"
          style={{
            backgroundImage: `radial-gradient(${isDarkMode ? '#ffffff' : '#000000'} 1px, transparent 1px)`,
            backgroundSize: '40px 40px'
          }}
        />
      </div>

      {/* Header */}
      <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 relative z-50 sticky top-0 transition-all duration-300 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 py-3 md:px-6 flex items-center justify-between">
          <div className="flex flex-col select-none cursor-pointer group" onClick={() => window.location.reload()}>
            <div className="flex items-center gap-2">
              <div className="bg-gradient-to-br from-blue-600 to-indigo-700 text-white px-3 py-1 font-black text-lg md:text-xl rounded-lg shadow-lg shadow-blue-500/20 transition-transform group-hover:scale-105">
                {t('app_title')}
              </div>
              <span className="font-bold text-lg md:text-xl tracking-tight text-slate-900 dark:text-white">{t('app_subtitle')}</span>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-3">
            <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-xl p-1 text-slate-500 dark:text-slate-400 font-medium text-xs">
              <button onClick={handleZoomOut} disabled={zoomLevel <= 60} className="p-1.5 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all disabled:opacity-30"><ZoomOut className="w-4 h-4" /></button>
              <div onClick={resetZoom} className="px-3 cursor-pointer hover:text-blue-600 transition-colors">{zoomLevel}%</div>
              <button onClick={handleZoomIn} disabled={zoomLevel >= 150} className="p-1.5 hover:bg-white dark:hover:bg-slate-700 rounded-lg transition-all disabled:opacity-30"><ZoomIn className="w-4 h-4" /></button>
            </div>

            <button 
              onClick={() => setIsInfoModalOpen(true)}
              className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-all"
            >
              <Info className="w-5 h-5" />
            </button>

            <div className="relative">
              <button 
                onClick={() => setIsLangMenuOpen(!isLangMenuOpen)}
                className="px-4 py-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-700 dark:text-slate-300 font-semibold text-xs flex items-center gap-2 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all uppercase"
              >
                <Globe className="w-4 h-4" /> {language} <span className="text-[8px] opacity-50">▼</span>
              </button>

              {isLangMenuOpen && (
                <div className="absolute top-full right-0 mt-2 w-48 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl shadow-2xl z-50 overflow-hidden py-1">
                  {languages.map((lang) => (
                    <button
                      key={lang.code}
                      onClick={() => handleLanguageChange(lang.code)}
                      className={`w-full text-left px-4 py-2.5 text-xs font-semibold hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors flex items-center justify-between ${language === lang.code ? 'text-blue-600 bg-blue-50/50 dark:bg-blue-500/10' : 'text-slate-600 dark:text-slate-400'}`}
                    >
                      {lang.label}
                      {language === lang.code && <Check className="w-3 h-3" />}
                    </button>
                  ))}
                </div>
              )}
            </div>

            <button 
              onClick={toggleTheme}
              className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500 dark:text-slate-400 hover:text-yellow-500 dark:hover:text-yellow-400 transition-all"
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
          </div>
        </div>
      </header>

      <main 
        className="flex-grow relative z-10 flex flex-col items-center origin-top transition-transform duration-300 ease-out"
        style={{ 
          transform: `scale(${zoomLevel / 100})`,
          width: `${100 * (100 / zoomLevel)}%`
        }}
      >
        {children}
      </main>

      {/* Info Modal */}
      {isInfoModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md transition-opacity" onClick={() => setIsInfoModalOpen(false)}></div>
          <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 w-full max-w-2xl rounded-3xl shadow-2xl relative z-10 max-h-[90vh] overflow-hidden flex flex-col">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <div className="bg-blue-50 dark:bg-blue-900/30 p-2 rounded-xl">
                   <Info className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-900 dark:text-white uppercase tracking-tight">
                   {t('about_title')}
                 </h2>
              </div>
              <button 
                onClick={() => setIsInfoModalOpen(false)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
              >
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>

            <div className="p-8 space-y-8 overflow-y-auto custom-scrollbar flex-grow">
               <div>
                  <p className="text-base text-slate-600 dark:text-slate-400 leading-relaxed font-medium">
                    {t('about_desc')}
                  </p>
                  <p className="mt-4 text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">
                    {t('about_created_by')}
                  </p>
               </div>

               <div className="bg-slate-50 dark:bg-slate-800/50 rounded-2xl p-6">
                  <h3 className="text-sm font-bold uppercase tracking-wider mb-4 flex items-center gap-2 text-slate-900 dark:text-white">
                    <Star className="w-4 h-4 text-yellow-500 fill-yellow-500" /> {t('about_features')}
                  </h3>
                  <ul className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     {[t('feat_1'), t('feat_2'), t('feat_3'), t('feat_4')].map((feat, idx) => (
                       <li key={idx} className="flex items-center gap-2.5 text-xs font-semibold text-slate-600 dark:text-slate-300">
                         <div className="p-1 bg-green-500/10 rounded-full"><Check className="w-3 h-3 text-green-500" /></div> {feat}
                       </li>
                     ))}
                  </ul>
               </div>

               <div>
                  <h3 className="text-sm font-bold uppercase tracking-wider mb-4 flex items-center gap-2 text-slate-900 dark:text-white">
                    <Zap className="w-4 h-4 text-blue-600 dark:text-blue-400" /> {t('about_howto')}
                  </h3>
                  <div className="grid grid-cols-1 gap-4">
                    {[t('step_1'), t('step_2'), t('step_3'), t('step_4')].map((step, idx) => (
                      <div key={idx} className="flex items-center gap-4 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700/50 p-3 rounded-2xl">
                        <div className="bg-slate-100 dark:bg-slate-700 text-slate-900 dark:text-white w-8 h-8 flex items-center justify-center font-bold rounded-xl text-sm shrink-0">
                          {idx + 1}
                        </div>
                        <p className="text-sm font-medium text-slate-700 dark:text-slate-300">{step}</p>
                      </div>
                    ))}
                  </div>
               </div>
            </div>

            <div className="p-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30 flex justify-between items-center">
               <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t('version')}</span>
               <button 
                 onClick={() => setIsInfoModalOpen(false)}
                 className="px-6 py-2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-bold text-xs uppercase tracking-wider hover:opacity-90 transition-opacity"
               >
                 {t('close')}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

