/* ============================= */
/* 🎨 MODERN BLUE THEME SYSTEM */
/* ============================= */

:root {
  --primary: #1E3A8A;
  --primary-light: #2563EB;
  --primary-soft: #DBEAFE;

  --background: #F8FAFC;
  --card-bg: #FFFFFF;
  --border: #E2E8F0;

  --text-main: #0F172A;
  --text-secondary: #475569;
}

/* ============================= */
/* 🌍 GLOBAL */
/* ============================= */

body {
  background: linear-gradient(135deg, #EFF6FF, #F8FAFC);
  color: var(--text-main);
  font-family: 'Inter', sans-serif;
}

/* ============================= */
/* 🧱 CARD STYLE (GANTI SHADOW TEBAL) */
/* ============================= */

.card,
.feature-box,
.container-box {
  background: var(--card-bg);
  border: 1px solid var(--border);
  border-radius: 16px;
  box-shadow: 0 10px 30px rgba(30, 58, 138, 0.08);
  transition: all 0.3s ease;
}

.card:hover,
.feature-box:hover {
  transform: translateY(-4px);
  box-shadow: 0 15px 35px rgba(37, 99, 235, 0.15);
}

/* ============================= */
/* 🔵 TITLE & HEADLINE */
/* ============================= */

h1, h2, h3 {
  color: var(--primary);
}

/* ============================= */
/* 🚀 BUTTON MODERN */
/* ============================= */

.button-primary,
.btn-primary {
  background: linear-gradient(135deg, #2563EB, #1E40AF);
  color: white;
  border: none;
  border-radius: 12px;
  padding: 14px 24px;
  font-weight: 600;
  box-shadow: 0 8px 20px rgba(37, 99, 235, 0.25);
  transition: all 0.3s ease;
}

.button-primary:hover,
.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 25px rgba(37, 99, 235, 0.35);
}

/* ============================= */
/* 🏷 LABEL / TAG */
/* ============================= */

.tag,
.badge {
  background: var(--primary-soft);
  color: var(--primary);
  padding: 6px 12px;
  border-radius: 8px;
  font-size: 12px;
  font-weight: 600;
}

/* ============================= */
/* 🔲 NAVBAR */
/* ============================= */

.navbar {
  background: white;
  border-bottom: 1px solid var(--border);
}

/* ============================= */
/* ✨ ICON BOX */
/* ============================= */

.icon-box {
  background: var(--primary-soft);
  color: var(--primary);
  border-radius: 12px;
  padding: 12px;
}

